-- 单一窗口字典数据（达梦 DM8）
-- 生成日期：2026-05-05
-- 来源说明：CIT.sql 字段注释 + 海关/单一窗口公开通关参数代码表。
-- 约定：字典编码统一使用 cit_*；重复执行会先删除 cit_* 字典及明细。
--
-- 字段映射：
--   cit_country_region (国别地区): DEC_HEAD.TRADE_COUNTRY, DEC_HEAD.TRADE_AREA_CODE, DEC_LIST.ORIGIN_COUNTRY, DEC_LIST.DESTINATION_COUNTRY, DEC_SUPPLEMENT.TRANSIT_COUNTRY
--   cit_currency (币制): DEC_HEAD.FEE_CURR, DEC_HEAD.INSUR_CURR, DEC_HEAD.OTHER_CURR, DEC_LIST.TRADE_CURR, DEC_SUPPLEMENT.CURR, SDD_TAX.FEE_CURR, SDD_TAX.INSUR_CURR, SDD_TAX.OTHER_CURR, DEC_ROYALTY_FEE.CURR
--   cit_trade_mode (监管方式): DEC_HEAD.TRADE_MODE, SDD_TAX.TRADE_MODE
--   cit_cut_mode (征免性质): DEC_HEAD.CUT_MODE, SDD_TAX.CUT_MODE
--   cit_traf_mode (运输方式): DEC_HEAD.TRAF_MODE, TRN_HEAD.NATIVE_TRAF_MODE, TRN_LIST.TRAF_MODE, DEC_SUPPLEMENT.TRAF_MODE
--   cit_trans_mode (成交方式): DEC_HEAD.TRANS_MODE, SDD_TAX.TRANS_MODE
--   cit_wrap_type (包装种类): DEC_HEAD.WRAP_TYPE, DEC_OTHER_PACK.PACK_TYPE
--   cit_unit (计量单位): DEC_LIST.FIRST_UNIT, DEC_LIST.G_UNIT, DEC_LIST.SECOND_UNIT, DEC_GOODS_LIMIT.LIC_WRTOF_QTY_UNIT
--   cit_duty_mode (征减免税方式): DEC_LIST.DUTY_MODE
--   cit_use_to (用途): DEC_LIST.USE_TO
--   cit_ie_flag (进出口标志): DEC_HEAD.IE_FLAG, SDD_TAX.IE_FLAG
--   cit_decl_trn_rel (报关/转关关系标志): DEC_HEAD.DECL_TRN_REL
--   cit_edi_id (报关标志): DEC_HEAD.EDI_ID
--   cit_entry_type (报关单类型): DEC_HEAD.ENTRY_TYPE
--   cit_dec_type_prefix (单据类型前缀): DEC_HEAD.TYPE 的前两位
--   cit_fee_mark (运保杂费标记): DEC_HEAD.FEE_MARK, DEC_HEAD.INSUR_MARK, DEC_HEAD.OTHER_MARK, SDD_TAX.FEE_MARK, SDD_TAX.INSUR_MARK, SDD_TAX.OTHER_MARK
--   cit_yes_no (1是0否): CHK_SURETY, CHECK_FLOW, ORIG_BOX_FLAG, IS_SECRET, IS_CUS_AUDIT, IS_CUS_PRICE_PRE_DETERMIN 等
--   cit_check_flag (勾选标志): NO_OTHER_PACK, TRANSITION_APPLY, CONDITIONAL_LIFTOFF_APPLY, PORT_DEST_MERGE_CHECK_APPLY
--   cit_tax_admin_mark (税收征管标记): DEC_HEAD.TAX_AAMIN_MARK
--   cit_bill_type (备案清单类型): DEC_HEAD.BILL_TYPE
--   cit_edoc_format_type (随附单据格式类型): EDOC_RELATION.EDOC_FOMAT_TYPE
--   cit_edoc_code (随附单证类别): EDOC_RELATION.EDOC_CODE
--   cit_license_doc_code (监管证件/单证代码): DEC_LICENSE_DOCUS.DOCU_CODE, ECO_RELATION.CERT_TYPE
--   cit_oper_type (签名操作类型): DEC_SIGN.OPER_TYPE
--   cit_domain_id (签名人分类): DEC_SIGN.DOMAIN_ID
--   cit_trn_trans_flag (转关类型): TRN_HEAD.TRANS_FLAG
--   cit_e_seal_flag (电子关锁标志): TRN_HEAD.E_SEAL_FLAG
--   cit_trn_type (转关单类型): TRN_HEAD.TRN_TYPE
--   cit_origin_mark (原产国地区标记位置): DEC_SUPPLEMENT.ORIGIN_MARK
--   cit_cert_standard (原产地标准): DEC_SUPPLEMENT.CERT_STANDARD
--   cit_agent_type (申报单位类型): DEC_SUPPLEMENT.AGENT_TYPE
--   cit_tax_royalty_decl_type (应税特许权使用费申报情形): DEC_ROYALTY_FEE.TAX_ROYALTY_DECL_TYPE
--   cit_pay_type (特许权使用费支付方式): DEC_ROYALTY_FEE.PAY_TYPE
--   cit_cop_promise_material (证明/声明材料代码): DEC_COP_PROMISE.DECLARATIO_MATERIAL_CODE
--
-- 未静态展开但仍属于代码/参数的数据：
--   关区/海关代码: DEC_HEAD.CUSTOM_MASTER, DEC_HEAD.IE_PORT, DEC_HEAD.PURP_ORG_CODE, SDD_TAX.DECL_PORT, DEC_SUPPLEMENT.DEST_PORT, DEC_SUPPLEMENT.DECL_PORT, DEC_SUPPLEMENT.DECISION_CUS
--   进出口岸/港口/境内目的地: DEC_HEAD.DISTINATE_PORT, DEC_HEAD.DESP_PORT_CODE, DEC_HEAD.ENTY_PORT_CODE, DEC_LIST.DEST_CODE
--   检验检疫机关/领证机关: DEC_HEAD.INSP_ORG_CODE, DEC_HEAD.VSA_ORG_CODE, DEC_HEAD.ORG_CODE（脚本注释中已标废弃）
--   商品/CIQ/禁限管制/危化品大库: DEC_LIST.CODE_TS, DEC_LIST.CIQ_CODE, DEC_CONTROL_MODEL.DECLARATION_CATEGORY_CODE, DEC_LIST.UN_CODE, DEC_LIST.DANG_PACK_TYPE
--   企业和业务编号: AGENT_CODE, COP_CODE, TRADE_CODE, OWNER_CODE, ENTRY_ID, LICENSE_NO, MANUAL_NO 等不是字典
--   按位存储复合字段: PROMISE_ITMES, BUSINESS_ITEMS, DATA_SOURCE, SPEC_DECL_FLAG, ROYALTY_FEE_TYPE, EDOC_TYPE, G_OPTIONS 需要拆成复选控件，不应直接作为单值字典

DELETE FROM "SYS_DICT_ITEM" WHERE "DICT_ID" IN (SELECT "ID" FROM "SYS_DICT" WHERE SUBSTR("DICT_CODE", 1, 4) = 'cit_');
DELETE FROM "SYS_DICT" WHERE SUBSTR("DICT_CODE", 1, 4) = 'cit_';

